import { useActionPageSchema } from '@pages/ActionPages/pages/PublicActionPage/ActionPageView/hooks/useActionPageSchema';
import { isValidEmail } from '@utils/validations/validations';
import { isValidPhoneNumber } from 'libphonenumber-js';
import { useTranslation } from 'react-i18next';
import * as yup from 'yup';

type UseVirtualTerminalSchemaProps = {
  cardZipRequired?: boolean;
  cvvRequired?: boolean;
  disallowedRegions: string[];
  isZipOnly?: boolean;
  proEnabled?: boolean;
  requireAddress?: boolean;
  requireEmail?: boolean;
  requireEmailOrPhone?: boolean;
  requireEmployerAddress?: boolean;
  requirePhone?: boolean;
};

export const useVirtualTerminalSchema = ({
  cardZipRequired,
  cvvRequired,
  disallowedRegions,
  isZipOnly,
  proEnabled,
  requireAddress,
  requireEmail,
  requireEmailOrPhone,
  requireEmployerAddress,
  requirePhone,
}: UseVirtualTerminalSchemaProps) => {
  const { t } = useTranslation('actionPagesBuilder');

  let schema = useActionPageSchema({
    cardZipRequired,
    cvvRequired,
    disallowedRegions,
    isDonation: true,
    isZipOnly,
    requireAddress,
    requireEmail,
    requireEmailOrPhone,
    requireEmployerAddress,
    requirePhone,
  });

  if (proEnabled && requireEmailOrPhone) {
    schema = schema.concat(
      yup.object().shape({
        email: yup
          .string()
          .transform((value) => value || undefined)
          .optional()
          .test('email_formatting', t('public.validation.email.formatting'), (email) => {
            if (!email) {
              return true;
            }

            return isValidEmail(email);
          }),
        phone: yup
          .string()
          .optional()
          .test(
            'phone_formatting',
            t('public.validation.phone.validity'),
            (phone, { createError, parent }) => {
              if (!phone) {
                return true;
              }

              if (!isValidPhoneNumber(phone, parent?.addressAttributes?.country || 'US')) {
                return createError({
                  message: t('public.validation.phone.validity'),
                  path: 'phone',
                });
              }

              return true;
            }
          ),
      })
    );
  }
  return schema;
};

